import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { Search, ShoppingCart, Menu, X } from 'lucide-react';

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const cartItems = useSelector((state) => state.cart?.items || []);
  const cartCount = cartItems.reduce((total, item) => total + item.quantity, 0);

  const categories = [
    { name: 'Living Room', sub: ['Sofas', 'TV Units', 'Coffee Tables', 'Bookshelves', 'Shoe Racks'] },
    { name: 'Bedroom', sub: ['Beds', 'Wardrobes', 'Dressers', 'Nightstands', 'Mattresses'] }
  ];

  return (
    <>
      <header className="w-full bg-white shadow-sm sticky top-0 z-50">
        <div className="container mx-auto px-4 py-3 flex items-center justify-between relative">

          {/* Mobile: Hamburger Menu Button */}
          <button className="md:hidden p-1 z-20" onClick={() => setIsMenuOpen(true)}>
            <Menu size={24} />
          </button>

          {/* Centered Brand Name on Mobile, Left on Desktop */}
          <Link to="/" className="absolute left-1/2 -translate-x-1/2 md:static md:translate-x-0 z-10">
            <h1 className="text-xl font-bold tracking-tight text-gray-900 whitespace-nowrap">
              Videm's <span className="text-orange-500">Gallery</span>
            </h1>
          </Link>

          {/* Icons: Search & Cart */}
          <div className="flex items-center gap-4 z-20">
            <button className="p-1 text-gray-700">
              <Search size={24} />
            </button>
            <Link to="/cart" className="relative p-1 text-gray-700">
              <ShoppingCart size={24} />
              {cartCount > 0 && (
                <span className="absolute -top-1 -right-1 bg-orange-500 text-white text-[10px] font-bold h-4 w-4 rounded-full flex items-center justify-center">
                  {cartCount}
                </span>
              )}
            </Link>
          </div>
        </div>

        {/* Desktop Navigation Links */}
        <div className="hidden md:block w-full border-t border-gray-100 bg-white">
          <div className="container mx-auto px-4 py-3">
            <ul className="flex items-center justify-center space-x-12">
              {['LIVING ROOM', 'BEDROOM', 'DINING', 'STUDY'].map((category) => (
                <li key={category}>
                  <Link to={`/products?category=${category.toLowerCase().replace(' ', '-')}`} className="text-sm font-bold text-gray-800 hover:text-orange-500 tracking-wide transition-colors">
                    {category}
                  </Link>
                </li>
              ))}
            </ul>
          </div>
        </div>
      </header>

      {/* Mobile Sidebar Menu (Overlay) */}
      {isMenuOpen && (
        <div className="fixed inset-0 bg-white z-50 md:hidden flex flex-col">
          <div className="p-4 border-b border-gray-100 flex items-center justify-between">
            <button onClick={() => setIsMenuOpen(false)}>
              <X size={24} />
            </button>
            <h1 className="text-xl font-bold tracking-tight text-gray-900">
              Videm's <span className="text-orange-500">Gallery</span>
            </h1>
            <div className="flex gap-4">
              <Search size={24} />
              <ShoppingCart size={24} />
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4">
            {categories.map((cat) => (
              <div key={cat.name} className="mb-6">
                <h2 className="text-lg font-semibold text-gray-900 mb-3">{cat.name}</h2>
                <ul className="space-y-3 ml-2">
                  {cat.sub.map((sub) => (
                    <li key={sub} className="text-gray-600">{sub}</li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
        </div>
      )}
    </>
  );
};

export default Navbar;
